// n8n Error Information Processor for Notifications
// Place this code in a Code node connected after an Error Trigger node

// Get all input items (error data from Error Trigger)
const items = $input.all();

// Process each error item
const processedErrors = items.map((item, index) => {
  const data = item.json;

  // Determine if this is a trigger error or execution error
  const isTriggerError = !!data.trigger;

  // Extract common information
  const workflowInfo = {
    id: data.workflow?.id || 'Unknown',
    name: data.workflow?.name || 'Unknown Workflow'
  };

  let errorDetails = {};
  let severity = 'ERROR';

  if (isTriggerError) {
    // Handle trigger node errors
    const triggerError = data.trigger?.error || {};

    errorDetails = {
      errorType: 'TRIGGER_ERROR',
      severity: 'CRITICAL',
      timestamp: triggerError.timestamp ? new Date(triggerError.timestamp).toISOString() : new Date().toISOString(),
      errorName: triggerError.name || 'Unknown Error',
      errorMessage: triggerError.message || triggerError.cause?.message || 'No error message available',
      stackTrace: triggerError.stack || triggerError.cause?.stack || 'No stack trace available',
      mode: data.trigger?.mode || 'trigger',
      nodeName: triggerError.node?.name || 'Trigger Node',
      nodeType: triggerError.node?.type || 'Unknown'
    };

    severity = 'CRITICAL';

  } else {
    // Handle execution errors
    const execution = data.execution || {};
    const error = execution.error || {};

    errorDetails = {
      errorType: 'EXECUTION_ERROR',
      severity: 'ERROR',
      timestamp: new Date().toISOString(),
      executionId: execution.id || 'Not saved',
      executionUrl: execution.url || 'Not available',
      retryOf: execution.retryOf || null,
      errorMessage: error.message || 'No error message available',
      stackTrace: error.stack || 'No stack trace available',
      lastNodeExecuted: execution.lastNodeExecuted || 'Unknown',
      executionMode: execution.mode || 'Unknown'
    };

    // Adjust severity if this is a retry
    severity = execution.retryOf ? 'WARNING' : 'ERROR';
  }

  // Build a human-readable notification message
  const notificationMessage = buildNotificationMessage(
    workflowInfo,
    errorDetails,
    isTriggerError
  );

  // Return structured data for notification systems
  return {
    json: {
      // Notification-ready fields
      title: `🚨 Workflow Error: ${workflowInfo.name}`,
      message: notificationMessage,
      severity: severity,
      timestamp: errorDetails.timestamp,

      // Detailed information
      workflow: workflowInfo,
      error: errorDetails,

      // Quick action fields
      needsAttention: !errorDetails.retryOf,
      canRetry: !isTriggerError && errorDetails.executionId !== 'Not saved',

      // Raw data for advanced processing
      rawErrorData: data,

      // Formatted for different notification platforms
      formatted: {
        slack: formatForSlack(workflowInfo, errorDetails, isTriggerError),
        email: formatForEmail(workflowInfo, errorDetails, isTriggerError),
        discord: formatForDiscord(workflowInfo, errorDetails, isTriggerError),
        teams: formatForTeams(workflowInfo, errorDetails, isTriggerError)
      }
    }
  };
});

// Helper function to build notification message
function buildNotificationMessage(workflow, error, isTrigger) {
  let message = `Workflow: ${workflow.name} (ID: ${workflow.id})\n`;
  message += `Time: ${error.timestamp}\n`;
  message += `Severity: ${error.severity}\n\n`;

  if (isTrigger) {
    message += `❌ Trigger Activation Failed\n`;
    message += `Node: ${error.nodeName}\n`;
    message += `Type: ${error.nodeType}\n`;
  } else {
    message += `❌ Execution Failed\n`;
    message += `Execution ID: ${error.executionId}\n`;
    message += `Last Node: ${error.lastNodeExecuted}\n`;
    message += `Mode: ${error.executionMode}\n`;
    if (error.retryOf) {
      message += `⚠️ This is a retry of execution: ${error.retryOf}\n`;
    }
  }

  message += `\nError: ${error.errorMessage}\n`;

  // Add execution URL if available
  if (error.executionUrl && error.executionUrl !== 'Not available') {
    message += `\n🔗 View execution: ${error.executionUrl}`;
  }

  return message;
}

// Format for Slack
function formatForSlack(workflow, error, isTrigger) {
  const emoji = error.severity === 'CRITICAL' ? ':fire:' : ':x:';

  return {
    text: `${emoji} Workflow Error: ${workflow.name}`,
    blocks: [
      {
        type: "header",
        text: {
          type: "plain_text",
          text: `${emoji} Workflow Error Alert`,
          emoji: true
        }
      },
      {
        type: "section",
        fields: [
          {
            type: "mrkdwn",
            text: `*Workflow:*\n${workflow.name}`
          },
          {
            type: "mrkdwn",
            text: `*Severity:*\n${error.severity}`
          },
          {
            type: "mrkdwn",
            text: `*Time:*\n${error.timestamp}`
          },
          {
            type: "mrkdwn",
            text: isTrigger ? `*Node:*\n${error.nodeName}` : `*Last Node:*\n${error.lastNodeExecuted}`
          }
        ]
      },
      {
        type: "section",
        text: {
          type: "mrkdwn",
          text: `*Error Message:*\n\`\`\`${error.errorMessage}\`\`\``
        }
      }
    ]
  };
}

// Format for Email
function formatForEmail(workflow, error, isTrigger) {
  return {
    subject: `🚨 n8n Workflow Error: ${workflow.name}`,
    html: `
      <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
        <div style="background-color: #f44336; color: white; padding: 20px; border-radius: 5px 5px 0 0;">
          <h2 style="margin: 0;">🚨 Workflow Error Alert</h2>
        </div>
        <div style="background-color: #f5f5f5; padding: 20px; border-radius: 0 0 5px 5px;">
          <h3>${workflow.name}</h3>
          <table style="width: 100%; border-collapse: collapse;">
            <tr>
              <td style="padding: 8px; font-weight: bold;">Workflow ID:</td>
              <td style="padding: 8px;">${workflow.id}</td>
            </tr>
            <tr>
              <td style="padding: 8px; font-weight: bold;">Severity:</td>
              <td style="padding: 8px;"><span style="background-color: #f44336; color: white; padding: 4px 8px; border-radius: 3px;">${error.severity}</span></td>
            </tr>
            <tr>
              <td style="padding: 8px; font-weight: bold;">Time:</td>
              <td style="padding: 8px;">${error.timestamp}</td>
            </tr>
            ${isTrigger ? `
            <tr>
              <td style="padding: 8px; font-weight: bold;">Node:</td>
              <td style="padding: 8px;">${error.nodeName}</td>
            </tr>
            ` : `
            <tr>
              <td style="padding: 8px; font-weight: bold;">Execution ID:</td>
              <td style="padding: 8px;">${error.executionId}</td>
            </tr>
            <tr>
              <td style="padding: 8px; font-weight: bold;">Last Node:</td>
              <td style="padding: 8px;">${error.lastNodeExecuted}</td>
            </tr>
            `}
          </table>
          <div style="margin-top: 20px; padding: 15px; background-color: white; border-left: 4px solid #f44336; border-radius: 3px;">
            <h4 style="margin-top: 0;">Error Message:</h4>
            <pre style="background-color: #f5f5f5; padding: 10px; border-radius: 3px; overflow-x: auto;">${error.errorMessage}</pre>
          </div>
          ${error.executionUrl && error.executionUrl !== 'Not available' ? `
          <div style="margin-top: 20px; text-align: center;">
            <a href="${error.executionUrl}" style="display: inline-block; background-color: #2196F3; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px;">View Execution</a>
          </div>
          ` : ''}
        </div>
      </div>
    `,
    text: buildNotificationMessage(workflow, error, isTrigger)
  };
}

// Format for Discord
function formatForDiscord(workflow, error, isTrigger) {
  const color = error.severity === 'CRITICAL' ? 0xFF0000 : error.severity === 'ERROR' ? 0xFF5722 : 0xFFC107;

  return {
    embeds: [{
      title: "🚨 Workflow Error Alert",
      description: `**${workflow.name}** has encountered an error`,
      color: color,
      fields: [
        {
          name: "Workflow ID",
          value: workflow.id,
          inline: true
        },
        {
          name: "Severity",
          value: error.severity,
          inline: true
        },
        {
          name: "Timestamp",
          value: error.timestamp,
          inline: false
        },
        {
          name: isTrigger ? "Node" : "Last Node",
          value: isTrigger ? error.nodeName : error.lastNodeExecuted,
          inline: true
        },
        {
          name: "Error Message",
          value: `\`\`\`${error.errorMessage.substring(0, 1000)}\`\`\``,
          inline: false
        }
      ],
      timestamp: error.timestamp
    }]
  };
}

// Format for Microsoft Teams
function formatForTeams(workflow, error, isTrigger) {
  return {
    "@type": "MessageCard",
    "@context": "https://schema.org/extensions",
    "summary": `Workflow Error: ${workflow.name}`,
    "themeColor": "FF0000",
    "title": "🚨 Workflow Error Alert",
    "sections": [
      {
        "activityTitle": workflow.name,
        "activitySubtitle": `Severity: ${error.severity}`,
        "facts": [
          {
            "name": "Workflow ID:",
            "value": workflow.id
          },
          {
            "name": "Time:",
            "value": error.timestamp
          },
          {
            "name": isTrigger ? "Node:" : "Last Node:",
            "value": isTrigger ? error.nodeName : error.lastNodeExecuted
          },
          {
            "name": "Error:",
            "value": error.errorMessage
          }
        ],
        "markdown": true
      }
    ],
    "potentialAction": error.executionUrl && error.executionUrl !== 'Not available' ? [
      {
        "@type": "OpenUri",
        "name": "View Execution",
        "targets": [
          {
            "os": "default",
            "uri": error.executionUrl
          }
        ]
      }
    ] : []
  };
}

// Return processed items
return processedErrors;
